import requests, re, urllib.parse
base = 'http://localhost:80/static/'
sess = requests.Session()
seen = set()
files = []

def crawl(url):
    if url in seen: return
    seen.add(url)
    r = sess.get(url, timeout=10)
    if 'Index of' in r.text and '<a href' in r.text:
        # directory listing
        for href in re.findall(r'href="([^"]+)"', r.text):
            if href in ['/', '../', '/static/']: continue
            full = urllib.parse.urljoin(url, href)
            # avoid leaving /static/
            if not full.startswith(base):
                continue
            if href.endswith('/'):
                crawl(full)
            else:
                files.append(full)
    else:
        files.append(url)

crawl(base)

# Fetch files and search for interesting keywords
interesting = []
for f in files:
    try:
        r = sess.get(f, timeout=10)
        ct = r.headers.get('Content-Type','')
        text = r.text if 'text' in ct or 'html' in ct or ct=='' else ''
        if re.search(r'flag|FLAG|secret|SECRET|admin|DEBUG|key|SECRET_KEY', text):
            interesting.append((f, text[:1000]))
    except Exception as e:
        pass

print('FILES:', len(files))
for f in files:
    print(f)
print('\nINTERESTING:')
for f, snip in interesting:
    print('---', f, '\n', snip[:500], '\n')
